    self.name = ""                  -- 英雄备注名
    self.badgeWears = {}
end
function StructHeroAttribute:CreateByPb(pb)
    self.id = pb.id

    self.attrs={}
    local attrs=pb.attrs
    for i, v in ipairs(attrs) do
        local attr=self:CreateAttrEntry(v)
        table.insert(self.attrs,attr)
    end

    self.equips={}
    local equips=pb.equips
    for i, v in ipairs(equips) do
        local equip=StructEquip:New()
        equip:CreateByPb(v)
        --转换一次  
        --local equipAttr  = equip:GetServerData()
        table.insert(self.equips,equip)
    end

    self.playerId = pb.playerId

    self.heroRunes={}
    local heroRunes=pb.heroRunes
    for i, v in ipairs(heroRunes) do
        local heroRune=self:CreateHeroRune(v)
        table.insert(self.heroRunes,heroRune)
    end

    self.talentSkills = {}
    local talentSkills=pb.talentSkills
    for i, v in ipairs(talentSkills) do
        local talentSkill = self:CreateTalentSkill(v)
        table.insert(self.talentSkills,talentSkill)
    end

    self.open = pb.open

    self.outfits = {}
