    self.guildSkill = {}
    local guildSkills = pb.guildSkill
    for i, v in ipairs(guildSkills) do
        local guildSkill = self:CreateTalentSkill(v)
        table.insert(self.guildSkill,guildSkill)
    end

    local heroCoreContent
    if pb.coreContent then
        heroCoreContent = StructHeroCoreContent:New()
        heroCoreContent:CreateByPb(pb.coreContent)
    end
    self.coreContent = heroCoreContent

    local treeInfo = StructHeroTreeInfo:New()
    treeInfo:CreateByPb(pb.treeInfo)
    self.treeInfo = treeInfo

    self.sorceryCardInfo = {}
    if pb.sorceryCardInfo then
        self.sorceryCardInfo.scRefId =pb.sorceryCardInfo.scRefId
        self.sorceryCardInfo.level = pb.sorceryCardInfo.level
    end
    self.golemList = {}
    if pb.golemSuit then
        local golemSuit = pb.golemSuit
        for i,v in ipairs(golemSuit.golem) do
            local golemInfo = StructGolemInfo:New()
            golemInfo:CreateByPb(v)
            table.insert(self.golemList,golemInfo)
        end
    end

    -- 【G公共支持】删除伙伴晶石功能相关数据
