    self.name = pb.name
    local badgeWears = {}
    if pb.badgeWears then
        for _, value in ipairs(pb.badgeWears) do
            badgeWears[value.slot] = value
        end
    end
    self.badgeWears = badgeWears
end

--属性
function StructHeroAttribute:CreateAttrEntry(pb)
    local table={
        refId = pb.refId,
        value = pb.value,
    }
    return table
end

--符文
function StructHeroAttribute:CreateHeroRune(pb)
    local runeInfo=StructRune:New()
    runeInfo:CreateByPb(pb.runeInfo)
    runeInfo = runeInfo:GetServerData()
    local table={
        position=pb.position,
        runeInfo=runeInfo,
    }
    return table
end

--天赋技能
function StructHeroAttribute:CreateTalentSkill(pb)
    local table={
        position=pb.position,
        skillId=pb.skillId,
    }
    return table
end

return StructHeroAttribute